### API key auth (simplest)

Users include their key in every request:
```
Authorization: Bearer api_key_1234567890
```

**Generating and validating:**
```js
import crypto from 'crypto';

// Generate: store hash in DB, return plaintext once
const plainKey = `sk_${crypto.randomBytes(24).toString('hex')}`;
const keyHash = crypto.createHash('sha256').update(plainKey).digest('hex');
await db.apiKey.create({ data: { hash: keyHash, userId } });
// Return plainKey to user ONCE — you can't recover it later

// Validate per request
const authHeader = req.headers.authorization;
const key = authHeader?.replace('Bearer ', '');
if (!key) return res.status(401).json({ error: 'Missing API key' });
const hash = crypto.createHash('sha256').update(key).digest('hex');
const dbKey = await db.apiKey.findUnique({ where: { hash } });
if (!dbKey) return res.status(401).json({ error: 'Invalid API key' });
```

Protect your tool from abuse (and protect your Claude API costs):

```js
import rateLimit from 'express-rate-limit';

const limiter = rateLimit({
  windowMs: 60 * 1000,    // 1 minute window
  max: 20,                 // max 20 requests per minute per IP
  message: { error: 'Rate limit exceeded. Try again in a minute.' },
  standardHeaders: true,   // Return rate limit info in headers
  legacyHeaders: false,
});

// Apply globally
app.use('/api/', limiter);

// Or per-route (different limits for expensive routes)
const strictLimiter = rateLimit({ windowMs: 60000, max: 5 });
app.post('/api/summaries', strictLimiter, handleSummary);
```

`npm install express-rate-limit`

This limits by IP. For API key auth, limit per key instead.

```js
import Stripe from 'stripe';
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY);

// Create checkout session
app.post('/api/subscribe', async (req, res) => {
  const session = await stripe.checkout.sessions.create({
    mode: 'subscription',
    payment_method_types: ['card'],
    line_items: [{ price: process.env.STRIPE_PRICE_ID, quantity: 1 }],
    success_url: `${process.env.APP_URL}/dashboard?session={CHECKOUT_SESSION_ID}`,
    cancel_url: `${process.env.APP_URL}/pricing`,
    metadata: { userId: req.user.id }  // pass through your user ID
  });
  res.json({ url: session.url });
});

// Frontend: redirect to Stripe
const { url } = await fetch('/api/subscribe', { method: 'POST' }).then(r => r.json());
window.location.href = url; // Stripe handles the rest
```

`npm install stripe`

```js
// Webhook: needs raw body (before JSON parsing)
app.post('/api/webhooks/stripe',
  express.raw({ type: 'application/json' }),
  async (req, res) => {
    const sig = req.headers['stripe-signature'];
    let event;
    try {
      event = stripe.webhooks.constructEvent(
        req.body, sig, process.env.STRIPE_WEBHOOK_SECRET
      );
    } catch (err) {
      return res.status(400).send(`Webhook Error: ${err.message}`);
    }

    if (event.type === 'checkout.session.completed') {
      const session = event.data.object;
      const userId = session.metadata.userId;
      await db.user.update({
        where: { id: userId },
        data: { plan: 'pro', stripeCustomerId: session.customer }
      });
    }

    res.json({ received: true });
  }
);
```

Test webhooks locally: `stripe listen --forward-to localhost:3001/api/webhooks/stripe`

Install Stripe CLI: `brew install stripe/stripe-cli/stripe`

The simplest analytics: log key events to your database.

```js
// Log events in your API routes
app.post('/api/summaries', authenticate, async (req, res) => {
  const startTime = Date.now();
  try {
    const result = await runSummary(req.body.text);

    // Log success event
    await db.event.create({
      data: {
        userId: req.user.id,
        event: 'summary_created',
        properties: {
          inputLength: req.body.text.length,
          outputLength: result.length,
          durationMs: Date.now() - startTime,
          model: 'haiku'
        }
      }
    });

    res.json({ summary: result });
  } catch (err) {
    await db.event.create({ data: { userId: req.user.id, event: 'summary_failed', properties: { error: err.message } } });
    throw err;
  }
});
```

Query later: `SELECT event, COUNT(*) FROM events GROUP BY event, DATE(created_at)`

Cache results for identical inputs — many users ask similar things:

```js
import crypto from 'crypto';

function cacheKey(systemPrompt, userInput) {
  return crypto.createHash('sha256')
    .update(systemPrompt + '|' + userInput)
    .digest('hex');
}

app.post('/api/summarize', authenticate, async (req, res) => {
  const { text } = req.body;
  const key = cacheKey(SYSTEM_PROMPT, text);

  // Check cache first (TTL: 24 hours)
  const cached = await db.cache.findFirst({
    where: { key, createdAt: { gt: new Date(Date.now() - 86400000) } }
  });
  if (cached) {
    return res.json({ summary: cached.value, cached: true });
  }

  // Call Claude
  const summary = await runSummary(text);

  // Store in cache
  await db.cache.create({ data: { key, value: summary } });

  res.json({ summary, cached: false });
});
```

For content that rarely changes, a 24-hour cache can cut costs by 30-50%.

IP-based rate limiting isn't enough for authenticated tools. Limit per user:

```js
app.post('/api/summarize', authenticate, async (req, res) => {
  const userId = req.user.id;
  const plan = req.user.plan; // 'free' | 'pro'

  // Check monthly usage
  const startOfMonth = new Date(new Date().setDate(1));
  const usage = await db.event.count({
    where: { userId, event: 'summary_created', createdAt: { gte: startOfMonth } }
  });

  const limits = { free: 10, pro: 1000 };
  if (usage >= limits[plan]) {
    return res.status(429).json({
      error: `Monthly limit reached (${limits[plan]}). Upgrade to Pro for 1000/month.`,
      upgradeUrl: '/pricing'
    });
  }

  // Continue with API call...
});
```

This protects costs while giving a clear upgrade path. Free users hitting limits convert at 15-25%.
